from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a descriptor (without repeating the subject)
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language descriptor for a single predicate."""
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            low_obj = obj.lower()
            if low_obj in ("united states", "usa", "united states of america"):
                return "is an American"
            if low_obj.startswith("the "):
                return f"is from {obj}"
            else:
                return f"is from the {obj}"
        if p == "occupation":
            return f"was a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is retired"
            return f"is {low}"
        if p == "dateofretirement":
            return f"retired on {fmt_date(obj)}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "mission":
            return f"was a crew member of {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"was operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"{subj}'s backup pilot was {obj}"
        if p == "crewmembers":
            return f"{obj} was a crew member of {subj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # Generic fallback
        return f"is {obj}"

    # Group triples by subject
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        groups[t.subject].append(t)

    # Map missions to astronauts via 'mission' predicate
    mission_to_astronauts = defaultdict(list)
    astronaut_subjects_with_mission = set()
    for t in triples:
        if t.predicate == "mission":
            mission_to_astronauts[t.object].append(t.subject)
            astronaut_subjects_with_mission.add(t.subject)

    sentences = []

    # First handle each mission that has related triples
    for mission, astronauts in mission_to_astronauts.items():
        # descriptors for the mission itself
        mission_triples = groups.get(mission, [])
        descriptors = [phrase(mission, tr.predicate, tr.object) for tr in mission_triples]

        # add crew member descriptors from astronauts linked via the mission predicate
        for astro in astronauts:
            descriptors.append(phrase(astro, "mission", mission))

        if not descriptors:
            continue

        # Build clauses, ensuring each starts with the mission name if not already
        clauses = []
        for d in descriptors:
            d = d.strip()
            low = d.lower()
            if low.startswith(mission.lower()) or low.startswith("was"):
                clause = d
            else:
                clause = f"{mission} {d}"
            clauses.append(clause.rstrip('.'))

        if len(clauses) == 1:
            sent = f"{clauses[0]}."
        else:
            body = ", ".join(clauses[:-1])
            sent = f"{body}, and {clauses[-1]}."
        sentences.append(sent)

    # Now handle remaining subjects (excluding those already described as crew members)
    for subj, items in groups.items():
        if subj in astronaut_subjects_with_mission:
            continue
        descriptors = [phrase(subj, t.predicate, t.object) for t in items]
        if not descriptors:
            continue
        adjusted = []
        for d in descriptors:
            d = d.strip()
            if d.lower().startswith(subj.lower()):
                adjusted.append(d.rstrip('.'))
            else:
                adjusted.append(f"{subj} {d}")
        if len(adjusted) == 1:
            sent = f"{adjusted[0]}."
        else:
            body = ", ".join(adjusted[:-1])
            sent = f"{body}, and {adjusted[-1]}."
        sentences.append(sent)

    # Combine all generated sentences
    return " ".join(sentences)

